#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-28

# cc-backfill-changelog-ref.sh — migrate open cc-adoption issues to the stable
# `Changelog-Ref: <sha256>` dedup marker (#2041).
#
# Why: the filer used to dedup on `Key: <slug>+<version>`, but the slug is
# LLM-generated and drifts run-to-run, so re-triage filed DUPLICATES. The filer
# now keys on a hash of the verbatim changelog line. Issues that predate that
# change carry only the old `Key:` marker — so the first hash-keyed run would see
# them as "new" and file a duplicate STORM. This script adds the `Changelog-Ref:`
# marker to those issues FIRST (computed from the `> <changelog line>` already in
# each body), so the new key matches and dedup holds.
#
# Idempotent: issues already carrying `Changelog-Ref:` are skipped. Wired as a
# workflow step BEFORE cc-file-adoption-issues.sh; a cheap no-op once every issue
# is marked. Self-heals if any issue ever lacks the marker.
#
# Inputs (env):
#   GH_REPO        "owner/repo" — required
#   DRY_RUN        "1" → print actions, mutate nothing (default "0")
#   SLEEP_BETWEEN  seconds between edits (default 1; dodges gh secondary limit)
#
# Exit 0 on success (incl. no-op). Hard-fails on missing GH_REPO or gh errors.

set -euo pipefail

GH_REPO="${GH_REPO:?GH_REPO is required (owner/repo)}"
DRY_RUN="${DRY_RUN:-0}"
SLEEP_BETWEEN="${SLEEP_BETWEEN:-1}"

note() { echo "[backfill] $*"; }

# Portable sha256 of stdin → bare hex (must match cc-file-adoption-issues.sh).
sha256_hex() {
  if command -v sha256sum >/dev/null 2>&1; then sha256sum | cut -d' ' -f1; else shasum -a 256 | cut -d' ' -f1; fi
}

# MUST stay byte-identical to cc-file-adoption-issues.sh's normalize_ref — strip a
# leading bullet marker + collapse/trim whitespace so the backfilled key matches the
# filer's key for the same line (#2041).
normalize_ref() {
  sed -E 's/^[[:space:]]*[-*+][[:space:]]+//; s/[[:space:]]+/ /g; s/^[[:space:]]+//; s/[[:space:]]+$//'
}

backfilled=0
skipped=0
noref=0
while IFS= read -r num; do
  [ -z "${num:-}" ] && continue
  body=$(gh issue view "$num" -R "$GH_REPO" --json body --jq '.body')

  # Already migrated → skip (idempotent).
  if printf '%s' "$body" | grep -q 'Changelog-Ref:'; then
    skipped=$((skipped + 1))
    continue
  fi

  # The filer writes the verbatim changelog line as a `> <ref>` blockquote under
  # "## Changelog reference". Extract the first such line; that's the key source.
  ref=$(printf '%s\n' "$body" | sed -n 's/^> //p' | head -1)
  if [ -z "$ref" ]; then
    note "#${num}: no '> <ref>' line in body — can't key, leaving as-is"
    noref=$((noref + 1))
    continue
  fi
  hash=$(printf '%s' "$ref" | normalize_ref | sha256_hex)

  if [ "$DRY_RUN" = "1" ]; then
    note "DRY_RUN: would add Changelog-Ref \`${hash}\` to #${num}"
    backfilled=$((backfilled + 1))
    continue
  fi

  # Append the marker, preserving the existing body verbatim. The backticks are
  # intentionally LITERAL markdown (not command substitution), hence single quotes.
  # shellcheck disable=SC2016
  newbody=$(printf '%s\n\n**Changelog-Ref:** `%s`' "$body" "$hash")
  gh issue edit "$num" -R "$GH_REPO" --body "$newbody" >/dev/null
  note "#${num}: added Changelog-Ref \`${hash}\`"
  backfilled=$((backfilled + 1))
  sleep "$SLEEP_BETWEEN"
done < <(gh issue list -R "$GH_REPO" --label cc-adoption --state open --limit 300 \
  --json number --jq '.[].number')

note "done: backfilled=${backfilled}, already-marked=${skipped}, no-ref=${noref}."
